<script>
import { toRefs,reactive,onMounted,toRaw,ref } from 'vue';
import axios from 'axios';

export default {
  name:'MemberHome',
  setup(){
    let alertmsg=ref(false)
    let isLoading=ref(false)
    let memberInfo=reactive({
      fullName:'',
      email:'',
      phoneNumber:'',
      birth:'',
      address:''
    })
    let account=window.localStorage.getItem('isLogin')

    //頁面掛載完成之前，先向後端索取用戶資訊
    onMounted(() => {
      axios.get(`/userinfo?account=${account}`).then(
        response =>{
          console.log('請求發送成功!')
          console.log(response.data)
          memberInfo.fullName=response.data.fullName
          memberInfo.email=response.data.email
          memberInfo.phoneNumber='0'+response.data.phoneNumber
          memberInfo.address=response.data.address
          memberInfo.birth=response.data.birth
        }
      ).catch(
        error =>{
          console.log(error.message)
        }
      )
    })

    function userinfochangeconfirm(){
      document.body.scrollTop = 0
      document.documentElement.scrollTop = 0
      this.isLoading=true
      const changedUserData = toRaw(memberInfo)
      changedUserData.account=localStorage.getItem('isLogin')
      console.log(changedUserData)
      axios.post('/changeuserinfo',JSON.stringify(changedUserData),{ headers: { 'Content-Type': 'application/json' } }).then(
        response =>{
          console.log('請求發送成功',response.data)
          this.isLoading=false
          this.alertmsg=true
          setTimeout(() => {
            this.alertmsg=false
          }, 3000);
        }
      ).catch(
        error =>{
          console.log('請求發送失敗',error.message)

        }
      )
    }

    

    return{
      ...toRefs(memberInfo),
      userinfochangeconfirm,
      isLoading,
      alertmsg
    }
  }



};
</script>

